(function () {
  /* -------------------------------------------------------------------------
   * 静的検索: fuse-index.json を読み、?s= でフィルタ &rarr; 10件ずつ表示
   * ------------------------------------------------------------------------- */

  /** クエリ ?s= から検索語を取得（デコードして trim） */
  function getTerm() {
    try {
      var p = new URLSearchParams(window.location.search);
      var s = p.get('s') || '';
      try { s = decodeURIComponent(s); } catch (_) {}
      return (s + '').trim();
    } catch (_) {
      return '';
    }
  }

  /** クエリ ?page= からページ番号（1 始まり）。無ければ 1 */
  function getPage() {
    try {
      var p = new URLSearchParams(window.location.search);
      var raw = parseInt(p.get('page') || '1', 10);
      return raw > 0 ? raw : 1;
    } catch (_) {
      return 1;
    }
  }

  /** ヘッダー等の検索 input[name="s"] に、URL と同じ語を反映（静的 HTML の空/test 対策） */
  function syncSearchInputs(term) {
    try {
      var value = term || '';
      var inputs = document.querySelectorAll('input[name="s"]');
      inputs.forEach(function (input) {
        input.value = value;
      });
    } catch (_) {}
  }

  /** innerHTML 用に文字列をエスケープ */
  function escapeHtml(str) {
    return (str || '').replace(/[&"']/g, function (ch) {
      return ({
        '&': '&',
        '',
        '"': '"',
        "'": '''
      })[ch];
    });
  }

  /**
   * 記事・タグリンク用。外部 URL はそのまま。
   * 相対パスはデコード、末尾 index.html 除去、先頭を / にそろえる。
   */
  function normalizeInternalUrl(url) {
    var v = (url || '').trim();
    if (!v) return '#';
    if (/^https?:\/\//i.test(v)) return v;
    try { v = decodeURIComponent(v); } catch (_) {}
    v = v.replace(/\/index\.html$/i, '/');
    v = v.replace(/\/{2,}/g, '/');
    if (v.charAt(0) !== '/') v = '/' + v;
    return v;
  }

  /**
   * 検索語にマッチするか。マッチ時は表示優先度 { tier, sub } を返す。
   * tier: 3=タイトル &rarr; 2=本文（content / excerpt / summary の順で強い）&rarr; 1=その他（タグ名・著者・イベント日など）
   * sub: 同一 tier 内は「先頭に近い一致」ほど上位（数値が小さいほど良い）
   */
  function getSearchMatchRank(item, term) {
    var t = (term || '').toLowerCase();
    if (!t) {
      return null;
    }

    var title = (item.title || '').toLowerCase();
    var ti = title.indexOf(t);
    if (ti !== -1) {
      return { tier: 3, sub: ti };
    }

    var content = (item.content || '').toLowerCase();
    var excerpt = (item.excerpt || '').toLowerCase();
    var summary = (item.summary || '').toLowerCase();
    var ci = content.indexOf(t);
    var ei = excerpt.indexOf(t);
    var si = summary.indexOf(t);
    if (ci !== -1) {
      return { tier: 2, sub: ci };
    }
    if (ei !== -1) {
      return { tier: 2, sub: 100000 + ei };
    }
    if (si !== -1) {
      return { tier: 2, sub: 200000 + si };
    }

    var best = 999999;
    var consider = function (s) {
      var u = (s || '').toLowerCase();
      var i = u.indexOf(t);
      if (i !== -1 && i < best) {
        best = i;
      }
    };
    if (Array.isArray(item.tags)) {
      item.tags.forEach(function (tag) {
        consider(typeof tag === 'string' ? tag : '');
      });
    }
    if (Array.isArray(item.tags_detail)) {
      item.tags_detail.forEach(function (x) {
        consider(x && x.name ? x.name : '');
      });
    }
    consider(item.author);
    consider(item.event_date);

    if (best !== 999999) {
      return { tier: 1, sub: best };
    }
    return null;
  }

  /** ヒット判定（検索語が空のときは一覧全体対象のため true） */
  function includesTerm(item, term) {
    var t = (term || '').toLowerCase();
    if (!t) {
      return true;
    }
    return getSearchMatchRank(item, term) !== null;
  }

  /** 表示順: tier 降順 &rarr; sub 昇順 &rarr; objectID で安定ソート */
  function compareSearchRank(a, b, term) {
    var ra = getSearchMatchRank(a, term);
    var rb = getSearchMatchRank(b, term);
    if (!ra || !rb) {
      return 0;
    }
    if (rb.tier !== ra.tier) {
      return rb.tier - ra.tier;
    }
    if (ra.sub !== rb.sub) {
      return ra.sub - rb.sub;
    }
    var ida = parseInt(a.objectID, 10) || 0;
    var idb = parseInt(b.objectID, 10) || 0;
    return idb - ida;
  }

  /** PC 用: article-media 相当の 1 件分 HTML */
  function buildPcItem(item) {
    var title = escapeHtml(item.title || '');
    var url = escapeHtml(normalizeInternalUrl(item.path || item.url || '#'));
    var summary = escapeHtml((item.summary || item.excerpt || '').replace(/&hellip;/g, '...'));
    var thumb = escapeHtml(item.thumbnail || '');
    var author = escapeHtml(item.author || '');
    var date = escapeHtml(item.date || '');
    var isEvent = !!item.is_event;
    var eventDate = escapeHtml(item.event_date || '');
    var tags = Array.isArray(item.tags_detail) ? item.tags_detail.slice(0, 8) : [];
    var tagsHtml = tags.map(function (tag) {
      var tName = escapeHtml(tag.name || '');
      var tUrl = escapeHtml(normalizeInternalUrl(tag.url || '#'));
      return '#' + tName + '';
    }).join('');
    return '' +
      '' +
        '' +
          '' + title + '' +
          (isEvent ? 'イベント' + eventDate + '' : '') +
          (tagsHtml ? '' + tagsHtml + '' : '') +
          (!isEvent && summary ? '' + summary + '' : '') +
          (!isEvent && (author || date) ? '' + author + '' + date + '' : '') +
        '' +
        (thumb ? '' : '') +
      '';
  }

  /** SP 用: recommend_item 相当の 1 件分 HTML */
  function buildSpItem(item) {
    var title = escapeHtml(item.title || '');
    var url = escapeHtml(normalizeInternalUrl(item.path || item.url || '#'));
    var summary = escapeHtml((item.summary || item.excerpt || '').replace(/&hellip;/g, '...'));
    var thumb = escapeHtml(item.thumbnail || '');
    var author = escapeHtml(item.author || '');
    var date = escapeHtml(item.date || '');
    var isEvent = !!item.is_event;
    var eventDate = escapeHtml(item.event_date || '');
    var tags = Array.isArray(item.tags_detail) ? item.tags_detail.slice(0, 8) : [];
    var tagsHtml = tags.map(function (tag) {
      var tName = escapeHtml(tag.name || '');
      var tUrl = escapeHtml(normalizeInternalUrl(tag.url || '#'));
      return '#' + tName + '';
    }).join('');
    return '' +
      '' +
        '' +
          '' + title + '' +
          (thumb ? '' : '') +
        '' +
        (isEvent ? 'イベント' + eventDate + '' : '') +
        (!isEvent && summary ? '' + summary + '' : '') +
        (tagsHtml ? '' + tagsHtml + '' : '') +
        (!isEvent && (author || date) ? '' + author + '' + date + '' : '') +
      '';
  }

  /** 同じパスで ?s= / ?page= だけ差し替えた URL（ページネーションリンク用） */
  function buildSearchUrl(term, page) {
    var u = new URL(window.location.href);
    var path = u.pathname;
    if (/\/index\.html$/i.test(path)) {
      u.pathname = path.replace(/\/index\.html$/i, '/');
    }
    if (term) {
      u.searchParams.set('s', term);
    } else {
      u.searchParams.delete('s');
    }
    if (page > 1) {
      u.searchParams.set('page', String(page));
    } else {
      u.searchParams.delete('page');
    }
    return u.toString();
  }

  /**
   * ページネーションネーション
   */
  function getSlidingPageRange(currentPage, totalPages, delta) {
    var pageid = currentPage;
    var minSurplus = (pageid = (totalPages - delta))
      ? (pageid - (totalPages - delta))
      : 0;
    var first = Math.max(pageid - delta - maxSurplus, 1);
    var last = Math.min(pageid + delta + minSurplus, totalPages);
    return { first: first, last: last };
  }

  function appendPcPageLi(html, term, pageNum, currentPage) {
    if (pageNum === currentPage) {
      return html + '' + pageNum + '';
    }
    return html + '' + pageNum + '';
  }

  function renderPcPagination(term, currentPage, totalPages) {
    var container = document.getElementById('static-search-pagination-pc');
    if (!container) return;
    if (totalPages  1) {
      html += 'PREV';
    }
    if (currentPage < totalPages) {
      html += 'NEXT';
    }
    html += '';
    container.innerHTML = html;
    container.style.display = 'block';
  }

  /**
   * 見出し・入力同期・結果リスト・ページネーションを一括更新。
   * totalCount が 0 のときはリストを空にし、メッセージは出さない。
   */
  function render(results, term, totalCount, currentPage, totalPages) {
    var termPc = document.getElementById('static-search-term-pc');
    var termSp = document.getElementById('static-search-term-sp');
    if (termPc) termPc.textContent = term || 'すべて';
    if (termSp) termSp.textContent = term || 'すべて';
    syncSearchInputs(term);

    var pcContainer = document.getElementById('static-search-results-pc');
    var spContainer = document.getElementById('static-search-results-sp');
    if (!pcContainer || !spContainer) return;

    if (!totalCount) {
      pcContainer.innerHTML = '';
      spContainer.innerHTML = '';
      renderPcPagination(term, 1, 1);
      renderSpPagination(term, 1, 1);
      return;
    }

    pcContainer.innerHTML = results.map(buildPcItem).join('');
    spContainer.innerHTML = results.map(buildSpItem).join('');
    renderPcPagination(term, currentPage, totalPages);
    renderSpPagination(term, currentPage, totalPages);
  }

  /**
   * fuse-index.json を取得 &rarr; フィルタ &rarr; タイトル優先などでソート &rarr; ページ分割して render。
   * （Simply Static / SSP の管理画面設定はこのソート順には直接効かない）
   */
  async function run() {
    var term = getTerm();
    var page = getPage();
    var perPage = 10;

    var configMeta = document.querySelector("meta[name='ssp-config-path']");
    if (!configMeta) {
      render([], term, 0, 1, 1);
      return;
    }

    var configPath = configMeta.getAttribute('content') || '';
    var versionMeta = document.querySelector("meta[name='ssp-config-version']");
    var version = versionMeta ? versionMeta.getAttribute('content') : '';
    var suffix = version ? ('?ver=' + encodeURIComponent(version)) : '';
    var indexUrl = window.location.origin + configPath + 'fuse-index.json' + suffix;

    try {
      var res = await fetch(indexUrl, { headers: { 'Content-Type': 'application/json' } });
      if (!res.ok) throw new Error('fetch failed');
      var json = await res.json();
      var all = Object.values(json || {});
      var filtered = term ? all.filter(function (item) { return includesTerm(item, term); }) : all;
      if (term) {
        filtered.sort(function (a, b) {
          return compareSearchRank(a, b, term);
        });
      }
      var totalCount = filtered.length;
      var totalPages = Math.max(1, Math.ceil(totalCount / perPage));
      var currentPage = Math.min(page, totalPages);
      var start = (currentPage - 1) * perPage;
      var paged = filtered.slice(start, start + perPage);
      render(paged, term, totalCount, currentPage, totalPages);
    } catch (_) {
      render([], term, 0, 1, 1);
    }
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', run);
  } else {
    run();
  }
})();






